output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT DISTINCT ?stadium ?stadiumLabel WHERE {
  ?club wdt:P31 wd:Q13235 ; wdt:P275 wd:Q41740769 ; wdt:P275 wd:Q113548802 .
  ?club wdt:P637 ?stadium .
  OPTIONAL {
    ?stadium rdfs:label ?stadiumLabel .
    FILTER(langMatches(lang(?stadiumLabel) , "en"))
  }
}

